function(g, rect, comp, data, view) {
var startColor = (data && data.a('startColor')) || 'red';
var endColor = (data && data.a('endColor')) || 'black';
var radius = (data && data.a('radius')) || 1;
var centerX = rect.x + rect.width / 2;
var centerY = rect.y + rect.height / 2;    
var grd = g.createRadialGradient(centerX, centerY, 0, centerX, centerY, radius * Math.max(rect.width, rect.height));
grd.addColorStop(0, startColor);
grd.addColorStop(1, endColor);
g.fillStyle = grd;
g.fillRect(0, 0, rect.width, rect.height);
}
